INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2116, 213927, 7, 361, 'yesterday once more三', '冷雨夜，回忆着昨日的点滴。《他一定的很爱你》的旋律陪伴着我，听着阿杜特有的歌喉所演绎出的歌，看着窗外的大雨，心中不免涌起丝许沧桑；
<br> 
<br> 
<br>与她在一起度过的星期天里，印象有很多次也是下着大雨。我撑着伞，伞下的她靠我很近。似乎这理所当然，尽我身为她男友的义务，我总是把伞倾斜她头顶，而自己半个身体任凭雨淋。我不清楚她是否能知晓这细节，而事实却如此。想起某个星期天里，和她从南普陀爬山沿途翻越到了万石植物园内，在幸福园里躲着雨。依稀还记得当时的场景，在她的小本子里亲手写下几句话，内容大概是今生一定保护她或爱她永不变心之类的话吧！那一天的我俩过得很充实，很开心。面对着大山，我大声喊到：我爱你。。。淋着雨，陪着她，一直到雨稍微歇息。与她一起来到火车站卡乐美食广场，我记得很清楚，当时为了找位置填饱肚子，等了许久才有位置。而她，似乎对美食不太感兴趣，只看着我狼吞虎咽。这之后，送她上车各自回到了家。夜里，线上的她依旧与我重复着每日新的话题。似乎与她一起总有说不尽的言语。
<br> 
<br> 
<br>脑海中仍在搜索着逝去的日子，一样是个雨天，两个人在回品咖啡里，面对面坐着。那一日识两人之间的话语没平日的多，烛光下的她在我眼中显得特别动人。久久地望着她，沉默不语，努力地想要从她身上找出些什么来。每次跟她在一起的时光总是过得很快，不一会儿灰姑娘的故事发生在她身上，赶在十点前到家的她似乎很着急，并不在乎下雨天没有穿雨鞋。当然不管是否是因为迟回去与否，她脚上穿的鞋都不是水晶鞋。我很想当那位王子，但是事已愿违，我只能送她上车，然后独自回家。十一点左右，我俩又相逢在网络中。一样谈着风花雪月不着边际的话题。
<br> 
<br> 
<br>喜欢跟她在下雨的日子里逛街，或者坐在咖啡厅里透过玻璃望着街上匆忙躲雨的行人。雨天的她话总是不多，但这并不影响两个人在一起的浪漫气氛，只因我总会刻意去营造那氛围。与她在一起时，她仿佛是个很忠实的听众，耐心地倾听着我的心情或者笑话之类，从不插嘴。我喜欢这样的她，或者说我喜欢心爱的人愿意倾听我所说的每一句话，对我而言或对着我心爱的人而言，亦如此。可以说厦门大大小小的咖啡厅都曾留下过我和她的足迹，我喜欢在柔和优雅的咖啡厅里坐着，纵然不说话，望着心爱的她我都能感到无限满足。与她在一起的日子纵有再多烦心琐事，好象都与我无关。这一切只因她的存在，我心爱的人能够带给我很轻松，没有任何压力的感觉。有她相伴的日子总是令我开心喜悦无所顾虑。这样的情绪与日俱增，一直到今天，已经无法去想象说没有她的日子，我的生活将会如何改变。可以说对她的依赖性在我心底已经根深蒂固，我不想去改变，也永远不会改变的！
<br> 
<br> 
<br>雨仍下着，思念她的情绪伴着大雨声更浓了。昨日重现的下雨时节有她的存在，生活显得更有意义。一切都因爱她之深，恋她之切。只求这冷雨夜里的她也能思念着远方的我，伴随着雨声，渐渐入眠，脑海中带着她的身影而沉沉入眠。。。
<br>（未完待续）', '冷雨夜，回忆着昨日的点滴。《他一定的很爱你》的旋律陪伴着我，听着阿杜特有的歌喉所演绎出的歌，看着窗外的大雨，心中不免涌起丝许沧桑；

与她在一起度过的星期天里，印象有很多次也是下着大雨。我撑着伞，伞下的她靠我很近。似乎这理所当然，尽我身为她男友的义务，我总是把伞倾斜她头顶，而自己半个身体任凭雨淋。我不清楚她是否能知晓这细节，而事实却如此。想起某个星期天里，和她从南普陀爬山沿途翻越到了万石植物园内，在幸福园里躲着雨。依稀还记得当时的场景，在她的小本子里亲手写下几句话，内容大概是今生一定保护她或爱她永不变心之类的话吧！那一天的我俩过得很充实，很开心。面对着大山，我大声喊到：我爱你。。。淋着雨，陪着她，一直到雨稍微歇息。与她一起来到火车站卡乐美食广场，我记得很清楚，当时为了找位置填饱肚子，等了许久才有位置。而她，似乎对美食不太感兴趣，只看着我狼吞虎咽。这之后，送她上车各自回到了家。夜里，线上的她依旧与我重复着每日新的话题。似乎与她一起总有说不尽的言语。

脑海中仍在搜索着逝去的日子，一样是个雨天，两个人在回品咖啡里，面对面坐着。那一日识两人之间的话语没平日的多，烛光下的她在我眼中显得特别动人。久久地望着她，沉默不语，努力地想要从她身上找出些什么来。每次跟她在一起的时光总是过得很快，不一会儿灰姑娘的故事发生在她身上，赶在十点前到家的她似乎很着急，并不在乎下雨天没有穿雨鞋。当然不管是否是因为迟回去与否，她脚上穿的鞋都不是水晶鞋。我很想当那位王子，但是事已愿违，我只能送她上车，然后独自回家。十一点左右，我俩又相逢在网络中。一样谈着风花雪月不着边际的话题。

喜欢跟她在下雨的日子里逛街，或者坐在咖啡厅里透过玻璃望着街上匆忙躲雨的行人。雨天的她话总是不多，但这并不影响两个人在一起的浪漫气氛，只因我总会刻意去营造那氛围。与她在一起时，她仿佛是个很忠实的听众，耐心地倾听着我的心情或者笑话之类，从不插嘴。我喜欢这样的她，或者说我喜欢心爱的人愿意倾听我所说的每一句话，对我而言或对着我心爱的人而言，亦如此。可以说厦门大大小小的咖啡厅都曾留下过我和她的足迹，我喜欢在柔和优雅的咖啡厅里坐着，纵然不说话，望着心爱的她我都能感到无限满足。与她在一起的日子纵有再多烦心琐事，好象都与我无关。这一切只因她的存在，我心爱的人能够带给我很轻松，没有任何压力的感觉。有她相伴的日子总是令我开心喜悦无所顾虑。这样的情绪与日俱增，一直到今天，已经无法去想象说没有她的日子，我的生活将会如何改变。可以说对她的依赖性在我心底已经根深蒂固，我不想去改变，也永远不会改变的！

雨仍下着，思念她的情绪伴着大雨声更浓了。昨日重现的下雨时节有她的存在，生活显得更有意义。一切都因爱她之深，恋她之切。只求这冷雨夜里的她也能思念着远方的我，伴随着雨声，渐渐入眠，脑海中带着她的身影而沉沉入眠。。。

